     .execute(\\n307\\t                \u0026format!(\\n308\\t                    \\\"INSERT OR REPLACE INTO entities (collection, database_name, schema_name, id, version, data) {select_sql}\\\"\\n309\\t                ),\\n310\\t                [],\\n311\\t            )\\n312\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n313\\t        self.conn()?\\n314\\t            .execute(\\\"DROP TABLE entities_legacy\\\", [])\\n315\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n316\\t        Ok(())\\n317\\t    }\\n318\\t\\n319\\t    fn rebuild_schema_versions_table(\\n320\\t        \u0026self,\\n321\\t        has_database_name: bool,\\n322\\t        has_schema_name: bool,\\n323\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n324\\t        self.conn()?\\n325\\t            .execute_batch(\\n326\\t                \\\"ALTER TABLE schema_versions RENAME TO schema_versions_legacy;\\n327\\t                 CREATE TABLE schema_versions (\\n328\\t                     collection    TEXT NOT NULL,\\n329\\t                     database_name TEXT NOT NULL DEFAULT 'default',\\n330\\t                     schema_name   TEXT NOT NULL DEFAULT 'default',\\n331\\t                     version       INTEGER NOT NULL,\\n332\\t                     schema_json   TEXT NOT NULL,\\n333\\t                     created_at    INTEGER NOT NULL DEFAULT 0,\\n334\\t                     PRIMARY KEY (database_name, schema_name, collection, version)\\n335\\t                 );\\\",\\n336\\t            )\\n337\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n338\\t\\n339\\t        let select_sql = match (has_database_name, has_schema_name) {\\n340\\t            (true, true) =\u003e {\\n341\\t                \\\"SELECT collection,\\n342\\t                        COALESCE(database_name, 'default'),\\n343\\t                        COALESCE(schema_name, 'default'),\\n344\\t                        version,\\n345\\t                        schema_json,\\n346\\t  