chema_name: bool,\\n393\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n394\\t        self.conn()?\\n395\\t            .execute_batch(\\n396\\t                \\\"ALTER TABLE collection_views RENAME TO collection_views_legacy;\\n397\\t                 CREATE TABLE collection_views (\\n398\\t                     collection        TEXT NOT NULL,\\n399\\t                     database_name     TEXT NOT NULL DEFAULT 'default',\\n400\\t                     schema_name       TEXT NOT NULL DEFAULT 'default',\\n401\\t                     version           INTEGER NOT NULL,\\n402\\t                     view_json         TEXT NOT NULL,\\n403\\t                     updated_at_ns     INTEGER NOT NULL,\\n404\\t                     updated_by        TEXT,\\n405\\t                     PRIMARY KEY (database_name, schema_name, collection),\\n406\\t                     FOREIGN KEY (database_name, schema_name, collection)\\n407\\t                         REFERENCES collections(database_name, schema_name, name)\\n408\\t                         ON DELETE CASCADE\\n409\\t                 );\\\",\\n410\\t            )\\n411\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n412\\t\\n413\\t        let select_sql = match (has_database_name, has_schema_name) {\\n414\\t            (true, true) =\u003e {\\n415\\t                \\\"SELECT collection,\\n416\\t                        COALESCE(database_name, 'default'),\\n417\\t                        COALESCE(schema_name, 'default'),\\n418\\t                        version,\\n419\\t                        view_json,\\n420\\t                        updated_at_ns,\\n421\\t                        updated_by\\n422\\t                 FROM collection_views_legacy\\\"\\n423\\t            }\\n424\\t            _ =\u003e {\\n425\\t                \\\"SELECT v.collection,\\n426\\t                        COALESCE(c.database_name, 'default'),\\n427\\t                        COALESCE(c.schema_name, 'default'),\\n428\\t                      